import type { Chain, Address as EvmAddress } from 'viem';
import type { Address as SolanaAddress } from '@solana/kit';
import type { typedAddressSchema } from './schemas';
import type z from 'zod';

export type EthereumAddress = EvmAddress;
export { SolanaAddress };
export type MixedAddress = EthereumAddress | SolanaAddress;

export enum Network {
  BASE = 'base',
  TEMPO = 'tempo',
  SOLANA = 'solana',
}

export type EvmNetwork = Exclude<Network, Network.SOLANA>;

export interface BaseNetworkConfig {
  caip2: `${string}:${string}`;
  name: string;
}

export interface EvmNetworkConfig extends BaseNetworkConfig {
  chain: Chain;
  usdcAddress: EthereumAddress;
}

export interface SolanaNetworkConfig extends BaseNetworkConfig {
  usdcAddress: SolanaAddress;
}

export interface NetworkToken {
  symbol: string;
  name: string;
  icon: string;
  address: MixedAddress;
  decimals: number;
  network: Network;
}

export type TypedNetworkAddress = z.infer<typeof typedAddressSchema>;
