import z from 'zod';

import { Network } from './types';

import { isAddress } from 'viem';
import { isAddress as isSolanaAddress } from '@solana/kit';

import type { MixedAddress, SolanaAddress, EvmNetwork } from './types';
import { EVM_CONFIGS } from './configs';

export const networkSchema = z.enum(Network);
export const optionalNetworkSchema = networkSchema.optional();

export const evmNetworkSchema = z.enum(
  Object.keys(EVM_CONFIGS) as EvmNetwork[]
);

export const ethereumAddressSchema = z
  .string()
  .refine(isAddress, 'Invalid EVM address');

export const solanaAddressSchema: z.ZodType<SolanaAddress, string> = z
  .string()
  .refine(isSolanaAddress, 'Invalid Solana address');

export const mixedAddressSchema: z.ZodType<MixedAddress, string> = z
  .union([ethereumAddressSchema, solanaAddressSchema])
  .transform(address => address as MixedAddress);

export const typedAddressSchema = z.discriminatedUnion('network', [
  z.object({
    address: ethereumAddressSchema,
    network: evmNetworkSchema,
  }),
  z.object({
    address: solanaAddressSchema,
    network: z.literal(Network.SOLANA),
  }),
]);
