import { base, tempo } from 'viem/chains';

import { Network } from './types';

import type {
  EvmNetworkConfig,
  EvmNetwork,
  SolanaAddress,
  SolanaNetworkConfig,
  BaseNetworkConfig,
} from './types';

export const EVM_CONFIGS: Record<EvmNetwork, EvmNetworkConfig> = {
  [Network.BASE]: {
    chain: base,
    name: 'Base',
    caip2: 'eip155:8453',
    usdcAddress: '0x833589fCD6eDb6E08f4c7C32D4f71b54bdA02913',
  },
  [Network.TEMPO]: {
    chain: tempo.extend({
      feeToken: '0x20c000000000000000000000b9537d11c60e8b50',
    }),
    name: 'Tempo',
    caip2: 'eip155:4217',
    usdcAddress: '0x20c000000000000000000000b9537d11c60e8b50',
  },
};

export const chainId = (network: EvmNetwork) => EVM_CONFIGS[network].chain.id;

export const SOLANA_CONFIG: SolanaNetworkConfig = {
  name: 'Solana',
  caip2: 'solana:5eykt4UsFv8P8NJdTREpY1vzqKqZKvdp',
  usdcAddress: 'EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v' as SolanaAddress,
};

export const ALL_NETWORK_CONFIGS: Record<Network, BaseNetworkConfig> = {
  ...EVM_CONFIGS,
  [Network.SOLANA]: SOLANA_CONFIG,
};

export const networkToCaip2 = (network: Network) => {
  if (network === Network.SOLANA) {
    return SOLANA_CONFIG.caip2;
  }
  return EVM_CONFIGS[network].caip2;
};

export const TX_EXPLORER_URLS: Record<Network, string> = {
  [Network.BASE]: 'https://basescan.org/tx/',
  [Network.TEMPO]: 'https://testnet.tempo.xyz/tx/',
  [Network.SOLANA]: 'https://solscan.io/tx/',
};

export const getTxExplorerUrl = (
  txHash: string,
  network: Network = Network.BASE
) => `${TX_EXPLORER_URLS[network]}${txHash}`;

export const caip2ToNetwork = (caip2: `${string}:${string}`) => {
  if (caip2 === SOLANA_CONFIG.caip2) {
    return Network.SOLANA;
  }
  const evmNetwork = Object.entries(EVM_CONFIGS).find(
    ([, config]) => config.caip2 === caip2
  )?.[0];
  if (evmNetwork) {
    return evmNetwork as EvmNetwork;
  }
  return null;
};
