import { EVM_CONFIGS, SOLANA_CONFIG } from './configs';
import { Network } from './types';

import type { NetworkToken } from './types';

export const usdc = (network: Network): NetworkToken => ({
  symbol: 'USDC',
  name: 'USD Coin',
  icon: '/usdc.png',
  decimals: 6,
  network,
  address:
    network === Network.SOLANA
      ? SOLANA_CONFIG.usdcAddress
      : EVM_CONFIGS[network].usdcAddress,
});
